from flask import Flask, request, jsonify
import jwt

app = Flask(__name__)

@app.before_request
def validate_jwt():
    token = request.headers.get('Authorization')
    if not token:
        return jsonify({"error": "Missing Authorization header"}), 401
    
    try:
        # Decode the JWT without verifying the signature for development purposes
        user_claims = jwt.decode(token, options={"verify_signature": False})
        # Store user claims in a request context variable or pass them to backend services as needed
        request.user_claims = user_claims
    except jwt.ExpiredSignatureError:
        return jsonify({"error": "Token expired"}), 401
    except jwt.InvalidTokenError:
        return jsonify({"error": "Invalid token"}), 401

@app.route('/protected')
def protected():
    # Access the user claims stored in the request context variable
    user_claims = getattr(request, 'user_claims', None)
    if not user_claims:
        return jsonify({"error": "User claims not found"}), 403
    
    # Forward user claims to backend services as needed
    # This is a placeholder for actual API call to backend services
    return jsonify({"message": "Access granted", "user_claims": user_claims})

if __name__ == '__main__':
    app.run(debug=True)